// ============================================================
// O(n²) — every pair
// ============================================================
// Classic example: find all pairs that sum to a target.

function allPairsSumTo(arr, target) {
  const pairs = [];
  for (let i = 0; i < arr.length; i++) {
    for (let j = i + 1; j < arr.length; j++) {
      if (arr[i] + arr[j] === target) pairs.push([arr[i], arr[j]]);
    }
  }
  return pairs;
}

console.log(allPairsSumTo([1, 2, 3, 4, 5, 6], 7));
// [[1, 6], [2, 5], [3, 4]]

// Operations ≈ n(n-1)/2 ≈ n²/2. Still O(n²).
//
// There IS a smarter O(n) solution using a Set — for each x, check if (target - x) is in the set.
// Sometimes the n² version is fine for small inputs. Sometimes it's a disaster.

// ============================================================
// O(n³) — every triple
// ============================================================
// Naive 'find three numbers that sum to target'.

function allTriplesSumTo(arr, target) {
  const triples = [];
  for (let i = 0; i < arr.length; i++) {
    for (let j = i + 1; j < arr.length; j++) {
      for (let k = j + 1; k < arr.length; k++) {
        if (arr[i] + arr[j] + arr[k] === target) {
          triples.push([arr[i], arr[j], arr[k]]);
        }
      }
    }
  }
  return triples;
}

console.log(allTriplesSumTo([1, 2, 3, 4, 5], 9));
// [[1, 3, 5], [2, 3, 4]]

// Triple nested loop → O(n³).
// For n = 1000, that's 10⁹ ops — many seconds of CPU.
// Smarter algorithm: sort + two-pointer → O(n²).

// ============================================================
// O(2ⁿ) — naive recursive Fibonacci
// ============================================================
// Each call branches into TWO recursive calls. Tree depth is n.
// Total calls ≈ 2ⁿ. Vast amounts of redundant work.

let calls = 0;
function fib(n) {
  calls++;
  if (n < 2) return n;
  return fib(n - 1) + fib(n - 2);
}

for (const n of [10, 20, 30]) {
  calls = 0;
  fib(n);
  console.log(`fib(${n}) made ${calls.toLocaleString()} calls`);
}

// fib(10):     ~177 calls
// fib(20):  ~21,000 calls
// fib(30): ~2,690,000 calls
//
// Each +10 multiplies work by ~100. That's exponential growth.
// fib(50) would take MINUTES; fib(100) literally trillions of years.

// ============================================================
// O(n!) — factorial, the worst common complexity
// ============================================================
// Generating every permutation of an array. n! permutations exist.

function permutations(arr) {
  if (arr.length <= 1) return [arr];
  const result = [];
  for (let i = 0; i < arr.length; i++) {
    const rest = [...arr.slice(0, i), ...arr.slice(i + 1)];
    for (const perm of permutations(rest)) {
      result.push([arr[i], ...perm]);
    }
  }
  return result;
}

console.log('permutations of [1,2,3]:', permutations([1, 2, 3]));
// 6 permutations (3! = 6)

console.log('count for [1,2,3,4]:',     permutations([1, 2, 3, 4]).length); // 24
console.log('count for [1,2,3,4,5]:',   permutations([1, 2, 3, 4, 5]).length); // 120

// Even n=12 would take ~half a billion permutations.
// Real applications use SMARTER algorithms — e.g.
// branch-and-bound for TSP, dynamic programming on bitmasks, etc.

